import socket
import threading
import json
import time
import math

class Player:
    def __init__(self, id, position):
        self.id = id
        self.position = position

class GameServer:
    def __init__(self, host='127.0.0.1', port=5555):
        self.host = host
        self.port = port
        self.players = {}
        self.lock = threading.Lock()

    def start_server(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)
        print("Server started.")
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Connection from {addr}")
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        player_id = client_socket.recv(1024).decode()
        print(f"Player {player_id} connected.")
        self.players[player_id] = Player(player_id, (0, 0))  # Starting position

        while True:
            try:
                data = client_socket.recv(1024).decode()
                if not data:
                    break

                position = json.loads(data)
                self.update_player_position(player_id, position)

                game_state = self.collect_game_state(player_id)
                client_socket.sendall(json.dumps(game_state).encode())
            except ConnectionResetError:
                break
        self.remove_player(player_id)
        client_socket.close()

    def update_player_position(self, player_id, position):
        with self.lock:
            if player_id in self.players:
                self.players[player_id].position = position

    def collect_game_state(self, player_id):
        with self.lock:
            player_positions = {
                pid: player.position for pid, player in self.players.items() if pid != player_id
            }
        return player_positions

    def remove_player(self, player_id):
        with self.lock:
            if player_id in self.players:
                del self.players[player_id]
                print(f"Player {player_id} disconnected.")

def is_within_distance(pos1, pos2, distance):
    return math.sqrt((pos1[0] - pos2[0])**2 + (pos1[1] - pos2[1])**2) <= distance

def main():
    server = GameServer()
    server_thread = threading.Thread(target=server.start_server)
    server_thread.start()

if __name__ == "__main__":
    main()